  ('heelevel3-6f0ba476-moex-00364', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司平日對商品管理採用定期盤存制，本年度截至第二季季末相關存貨資料如下：期初存 貨$150,000、進貨$250,000、進貨運費$5,000、銷貨$527,000、銷貨退回$17,000。甲公司的定 價慣例係依成本加50%作為售價。請問以毛利率法估算第二季季末之期末存貨金額為何？', '["$65,000", "$150,000", "$255,000", "$340,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00365', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司X1年初以$1,000,000購入自用土地一筆，採重估價模式衡量，X1年底按該土地當日 公允價值$1,200,000進行重估價，該公司選擇將重估增值累積於權益直至處分該土地。X2年 底評估該土地已發生減損，估計可回收金額為$950,000。X3年底該公司評估該土地已認列之 減損已不復存在，估計可回收金額為$1,080,000。該公司應認列計入X3年本期淨利之減損迴 轉利益金額為何？', '["$0", "$50,000", "$80,000", "$120,000 32270"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00366', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初給予30位員工各200單位之認股權，該給予之條件為員工必須繼續服務3 年。甲公司估計每一認股權之公允價值為$18。X1年共有2位員工離職，甲公司估計既得期 間共有8位員工離職。X2年陸續又有3位員工離職，在考慮可能離職率後，甲公司估計既得 期間共有9位員工離職，未能取得其認股權。請問甲公司X2年認列之薪資費用為何？', '["$0", "$21,600", "$24,000", "$25,200"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00367', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', 'X1年底甲公司將成本$1,200,000商品售予乙公司，取得現金$1,500,000，並約定於X2年1月 底以$1,650,000買回該商品。若甲公司將此交易逕列為銷貨交易，則對X1年底財報影響之敘 述，何者正確？', '["銷貨毛利高估$300,000", "資產高估$1,200,000", "淨利低估$300,000", "負債低估$1,650,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00368', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司 X1 年初計畫資產公允價值為$600,000，確定給付義務現值為$700,000，X1 年當期服 務成本為$13,000，淨利息成本為$15,000，提撥退休基金$35,000，並支付退休金若干。X1年 底計畫資產公允價值為$615,000，確定給付義務現值為$688,000，且並無精算假設改變，則X1 年退休基金實際報酬為：', '["$20,000", "$60,000", "$75,000", "$100,000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00369', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司自X1年1月1日起向乙公司承租一部耐用年限6年之設備，租期5年，乙公司每年 年初收取租金$100,000，第一次收款日為X1年1月1日，租賃屆滿該設備估計殘值為$80,000。 甲公司保證租期屆滿該設備殘值至少為$60,000。若租賃開始日租賃之給付現值為$471,968（隱 含利率為 9%），租賃資產之公允價值為$484,966。甲公司採直線法提列折舊，租賃終了時需 返還設備給乙公司。若租賃屆滿日實際殘值為$50,000，則甲、乙公司於租賃屆滿日相關會計 處理之敘述，何者正確？', '["甲公司租期屆滿時租賃負債餘額為$60,000", "甲公司毋需認列返還租賃資產損失", "乙公司租期屆滿時應收租賃款餘額為$60,000", "乙公司應認列收回資產損失$30,000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00370', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日發行5年期附賣回權可轉換公司債50張，每張面額為$100,000，票 面利率為0%，收到現金總額為$5,000,000。該賣回權於X1年1月1日，以選擇權定價模式 計算之公允價值為$495,000。此外，發行時，相同條件但不附賣回權及轉換權之公司債公平利 率為4%；5年期、4%、1元複利現值為0.821927。請問甲公司X1年12月31日與上述交易 相關之資本公積與公司債折價餘額為何？', '["資本公積為$495,000，公司債折價為$890,365", "資本公積為$890,365，公司債折價為$164,385", "資本公積為$99,635，公司債折價為$4,190,635", "資本公積為$395,365，公司債折價為$725,980"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00371', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲航空公司與乙租賃公司於X1年1月1日簽訂不可撤銷之租賃契約，約定租用新客機乙架， 為期4年，每年租金8,000萬元。甲航空公司有權於租期屆滿時每年以2,000萬元續租5年， 同時得於 X6 年底以 4,000 萬元之購買權行使價格購買該客機（估計屆時公允價值為 80,000 萬元）。甲航空公司可合理確定將行使該選擇權。該客機之耐用年限為25年，但甲航空公司 之政策為機隊之機齡不超過15年。請問此租約之租期為何？', '["4年", "6年", "9年", "15年 32270"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
